module top_module(
    obf_In0,
    In1,
    In2,
    In3,
    Sel1,
    Sel2,
    Out
);input obf_In0, In1, In2, In3, Sel1, Sel2;
    output Out;

    reg Out;

    always @(*) begin
        case ({Sel1, Sel2})
            2'b00: Out = obf_In0;
